begin;
alter table public.habits add column if not exists habit_type text not null default 'simple' check (habit_type in ('simple','checklist'));
alter table public.habits add column if not exists completion_threshold_mode text not null default 'all' check (completion_threshold_mode in ('any','count','all'));
alter table public.habits add column if not exists completion_threshold_count smallint check (completion_threshold_count is null or completion_threshold_count > 0);
create table if not exists public.habit_actions (id uuid primary key default gen_random_uuid(),household_id uuid not null references public.households(id) on delete cascade,habit_id uuid not null references public.habits(id) on delete cascade,name text not null,display_order integer not null default 0,required boolean not null default true,active boolean not null default true,created_at timestamptz not null default now(),unique(habit_id,display_order));
create table if not exists public.habit_action_history (id uuid primary key default gen_random_uuid(),household_id uuid not null references public.households(id) on delete cascade,habit_id uuid not null references public.habits(id) on delete cascade,habit_date date not null,total_active_actions integer not null default 0,completed_count integer not null default 0,threshold_met boolean not null default false,completed_action_ids uuid[] not null default '{}',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(habit_id,habit_date));
create index if not exists habit_actions_habit_order_idx on public.habit_actions(habit_id,display_order) where active;
create index if not exists habit_action_history_household_date_idx on public.habit_action_history(household_id,habit_date desc);
alter table public.habit_actions enable row level security;alter table public.habit_action_history enable row level security;
grant select,insert,update,delete on public.habit_actions,public.habit_action_history to authenticated;
do $$ declare t text; begin foreach t in array array['habit_actions','habit_action_history'] loop execute format('drop policy if exists %I on public.%I',t||'_member_select',t);execute format('create policy %I on public.%I for select to authenticated using (exists (select 1 from public.household_members hm where hm.household_id=%I.household_id and hm.user_id=auth.uid() and hm.status=''active''))',t||'_member_select',t,t);execute format('drop policy if exists %I on public.%I',t||'_manager_all',t);execute format('create policy %I on public.%I for all to authenticated using (public.familyos_has_household_role(household_id,array[''owner'',''adult''])) with check (public.familyos_has_household_role(household_id,array[''owner'',''adult'']))',t||'_manager_all',t);end loop;end $$;
commit;
